const now = new Date();
const timeMin = now.toISOString();
const timeMax = new Date(now.getTime() + 48 * 3600000).toISOString();
return [{ json: { timeMin, timeMax } }];

const events = ($input.first().json.items || []);

const MONTHS = ['január','február','március','április','május','június',
  'július','augusztus','szeptember','október','november','december'];

// Filter: only confirmed events that have CLIENT_EMAIL in description
const toNotify = events.filter(ev => {
  const desc = ev.description || '';
  return ev.status === 'confirmed' && desc.includes('CLIENT_EMAIL:');
});

return toNotify.map(ev => {
  const desc = ev.description || '';
  const emailMatch = desc.match(/CLIENT_EMAIL:([^\n]+)/);
  const nameMatch  = desc.match(/CLIENT_NAME:([^\n]+)/);
  const svcMatch   = desc.match(/SERVICE:([^\n]+)/);

  const email   = emailMatch ? emailMatch[1].trim() : null;
  const name    = nameMatch  ? nameMatch[1].trim()  : 'Kedves Ügyfél';
  const service = svcMatch   ? svcMatch[1].trim()   : '';

  const dt = new Date(ev.start.dateTime || ev.start.date);
  const dateHU = `${dt.getFullYear()}. ${MONTHS[dt.getMonth()]} ${dt.getDate()}.`;
  const timeHU = ev.start.dateTime
    ? `${dt.getHours()}:${String(dt.getMinutes()).padStart(2,'0')}`
    : 'Egész nap';

  return { json: { email, name, service, dateHU, timeHU, hasEmail: !!email } };
});
